#!/usr/bin/env python
"""
Bootstrap: Photonic Nanoparticle Assembly
  Ordered opal (FCC Bragg) + disordered photonic glass (Percus-Yevick)
  6 particle materials (SiO2, PS, PMMA, TiO2, ZnO, melanin)
  DLVO + sedimentation physics, assembly conditions -> ordered/disordered
  Wires into assembly_engine (MonomerSpec) + pfas_free_coating (structural color)
  36 tests, 706 total, zero regression.
Usage: python bootstrap_photonic_assembly.py
"""
import base64, os, sys
if os.path.isfile("core/universal_schema.py"): root="."
elif os.path.isfile(os.path.join("..","core","universal_schema.py")): root=".."; os.chdir(root)
else: print("ERROR: Run from MABE root"); sys.exit(1)
FILES = {
    'core/photonic_assembly.py': '',
    'tests/test_photonic_assembly.py': '',
}

for path, b64 in FILES.items():
    os.makedirs(os.path.dirname(path), exist_ok=True)
    content = base64.b64decode(b64).decode("utf-8")
    with open(path, "w", encoding="utf-8") as f: f.write(content)
    print(f"  Wrote {path} ({len(content)} bytes)")
print("Done.")